// Variety Manager (F08 SS7): pure counting over event-log-derived inputs. Flags are inputs to
// the Beat Planner and Encounter Designer, never hard constraints.

import type { Pillar } from './templates.ts'
import type { LoopType } from './types.ts'

export interface VarietyInput {
  /** Types of the last completed core loops, oldest first (window of 5 applied here). */
  completedLoopTypes: LoopType[]
  /** Per-player pillar usage: all-time and across the last two sessions. */
  pillarUsage: Record<string, { total: Record<Pillar, number>; recentSessions: Record<Pillar, number> }>
  /** Cooperation events this session (assists claimed, group checks, openings consumed, ...). */
  coopEventsThisSession: number
  /** Consecutive coop-DEMANDING obstacles most recently placed. */
  coopDemandStreak: number
  /** Resolved intents per player this session. */
  resolvedIntents: Record<string, number>
}

export interface VarietyFlags {
  suggestAlternateType: boolean
  pillarStarved: { player: string; pillar: Pillar }[]
  coopLow: boolean
  coopFatigue: boolean
  /** Player id holding > 60% of resolved intents, or null. */
  spotlight: string | null
}

export const LOOP_TYPE_WINDOW = 5
export const SAME_TYPE_LIMIT = 3
export const COOP_FATIGUE_STREAK = 3
export const SPOTLIGHT_SHARE = 0.6
export const SPOTLIGHT_MIN_INTENTS = 10

const PILLARS: Pillar[] = ['combat', 'social', 'exploration']

export function dominantPillar(total: Record<Pillar, number>): Pillar | null {
  const ranked = PILLARS.map((p) => [p, total[p] ?? 0] as const).sort((a, b) => b[1] - a[1])
  return ranked[0][1] > 0 ? ranked[0][0] : null
}

export function computeVarietyFlags(input: VarietyInput): VarietyFlags {
  const window = input.completedLoopTypes.slice(-LOOP_TYPE_WINDOW)
  const tail = window.slice(-SAME_TYPE_LIMIT)
  const suggestAlternateType =
    tail.length === SAME_TYPE_LIMIT && tail.every((t) => t === tail[0])

  const pillarStarved: VarietyFlags['pillarStarved'] = []
  for (const [player, usage] of Object.entries(input.pillarUsage)) {
    const dominant = dominantPillar(usage.total)
    if (dominant && (usage.recentSessions[dominant] ?? 0) === 0) {
      pillarStarved.push({ player, pillar: dominant })
    }
  }

  const totalResolved = Object.values(input.resolvedIntents).reduce((a, b) => a + b, 0)
  let spotlight: string | null = null
  if (totalResolved >= SPOTLIGHT_MIN_INTENTS) {
    for (const [player, count] of Object.entries(input.resolvedIntents)) {
      if (count / totalResolved > SPOTLIGHT_SHARE) spotlight = player
    }
  }

  return {
    suggestAlternateType,
    pillarStarved,
    coopLow: input.coopEventsThisSession === 0,
    coopFatigue: input.coopDemandStreak >= COOP_FATIGUE_STREAK,
    spotlight,
  }
}

/** Renders flags as Beat Planner guidance lines (empty when nothing flags). */
export function varietyGuidance(flags: VarietyFlags): string[] {
  const lines: string[] = []
  if (flags.suggestAlternateType) lines.push('Vary the loop type - the last few loops repeated the same shape.')
  for (const starved of flags.pillarStarved) {
    lines.push(`Give ${starved.player} a ${starved.pillar} moment - their favorite pillar has gone unused.`)
  }
  if (flags.coopLow) lines.push('Weight toward a cooperative goal (braided pair or group effort) - no cooperation happened yet this session.')
  if (flags.coopFatigue) lines.push('Do NOT demand cooperation this beat (keep rewarding it) - the last obstacles all required it.')
  if (flags.spotlight) lines.push(`Create an opening for players other than ${flags.spotlight} - one player is dominating resolved actions.`)
  return lines
}
